final_sparql:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?key ?keyLabel (?m * ?f AS ?kg) ?itemMass ?frac WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type ?key ;
        fq:itemMass ?m ;
        fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ; fq:amount ?f ] .
  ?key rdfs:label ?keyLabel .
  FILTER(LANG(?keyLabel) = "en")
  FILTER(
    CONTAINS(LCASE(?keyLabel), "motor") ||
    CONTAINS(LCASE(?keyLabel), "wire") ||
    CONTAINS(LCASE(?keyLabel), "cable") ||
    CONTAINS(LCASE(?keyLabel), "electronics") ||
    CONTAINS(LCASE(?keyLabel), "embedded")
  )
}
ORDER BY DESC(?kg)

arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  FILTER( CONTAINS(LCASE(STR(?label)), "motor") || CONTAINS(LCASE(STR(?label)), "wir") || CONTAINS(LCASE(STR(?label)), "electronic") )
} LIMIT 50

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( CONTAINS(LCASE(STR(?label)), "component") )
}
LIMIT 50

