PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label ?comment WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  OPTIONAL { ?cls rdfs:comment ?comment }
  FILTER( STR(?label) = "Component" || STR(?label) = "Product" || STR(?label) = "Material" || STR(?label) = "Element" )
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT DISTINCT ?cls ?label WHERE {
  ?cls a owl:Class .
  ?cls rdfs:subClassOf ?root .
  ?root rdfs:label "Component" .
  OPTIONAL { ?cls rdfs:label ?label }
  FILTER(STRSTARTS(STR(?cls), "https://www.purl.org/futuram#elv"))
} LIMIT 100

