PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?key ?keyLabel (?m * ?f AS ?kg) (?m AS ?itemMass_kg) (?f AS ?frac_kgPerKg) WHERE {
  VALUES ?key {
    <https://www.purl.org/futuram#elvElectricMotor>
    <https://www.purl.org/futuram#elvEmbeddedElectronicsCables>
    <https://www.purl.org/futuram#elvEmbeddedElectronics>
    <https://www.purl.org/futuram#elvPowerElectronics>
  }
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type        ?key ;
        fq:itemMass     ?m ;
        fq:contains     [ fq:constituent <https://www.purl.org/futuram#Copper> ;
                          fq:amount     ?f ] .
  OPTIONAL { ?key rdfs:label ?keyLabel }
}
ORDER BY DESC(?kg)

