arguments.sparql_query:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

# Find scope nodes partOf the BEV segment C 2025 whole
SELECT DISTINCT ?node ?type ?itemMass WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        a ?type ;
        fq:itemMass ?itemMass .
}
LIMIT 60

PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

# Discover the Component root class
SELECT DISTINCT ?root ?label WHERE {
  ?root a <http://www.w3.org/2002/07/owl#Class> .
  OPTIONAL { ?root rdfs:label ?label }
  FILTER( CONTAINS(LCASE(STR(?label)), "component") )
}
LIMIT 30

PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

# Show direct subclasses of the BEV segment C 2025 whole
SELECT DISTINCT ?sub ?label WHERE {
  ?sub rdfs:subClassOf <https://www.purl.org/futuram#V0301030103_Y2025> .
  OPTIONAL { ?sub rdfs:label ?label }
}
LIMIT 50

