PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

# Read copper in motor, wiring (cables), and power electronics scopes within BEV seg-C 2025
SELECT ?key ?itemMass ?frac ?unc WHERE {
  VALUES ?key {
    <https://www.purl.org/futuram#elvBEV_elvElectricMotor_Y2025>
    <https://www.purl.org/futuram#elvBEV_elvEmbeddedElectronicsCables_Y2025>
