arguments.sparql_query:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

# Direct children of the BEV seg-C 2025 whole -> one row per direct component, copper kg each.
# Discover the set via subClassOf closure (skip aggregates to avoid double-count).
SELECT ?key (SAMPLE(?itemMass) AS ?m) (SAMPLE(?frac) AS ?f) (SAMPLE(?unc) AS ?u) WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        a ?key ;
        fq:itemMass ?itemMass ;
        fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ; fq:amount ?frac ; fq:relativeUncertainty ?unc ] .
  ?key rdfs:subClassOf+ <https://www.purl.org/futuram#V0301030103_Y2025> .
}
GROUP BY ?key
ORDER BY (SAMPLE(?itemMass) * SAMPLE(?frac)) DESC

