arguments.sparql_query:
PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdf:     <http://www.w3.org/2000/02/22-rdf-syntax-ns#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?node ?comp ?compLabel ?itemMass ?frac ?constituent ?conLabel WHERE {
  ?node futuram:partOf futuram:V0301030103_Y2025 ;
        rdf:type        ?comp ;
        fq:itemMass     ?itemMass ;
        fq:contains     ?cnode .
  ?cnode fq:constituent ?constituent ;
         fq:amount      ?frac .
  ?constituent rdfs:label ?conLabel .
  OPTIONAL { ?comp rdfs:label ?compLabel . }
  FILTER(CONTAINS(LCASE(STR(?conLabel)), "copper") || CONTAINS(LCASE(STR(?conLabel)), "cu"))
}
ORDER BY DESC(?itemMass)

