PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?cls ?parent ?parentLabel ?clsLabel WHERE {
  ?cls rdfs:subClassOf ?parent .
  FILTER( STRSTARTS(STR(?cls), "https://www.purl.org/futuram#elv") )
  FILTER( ?parent != futuram:Component && ?parent != <http://www.w3.org/2002/07/owl#Thing> )
  OPTIONAL { ?parent rdfs:label ?parentLabel }
  OPTIONAL { ?cls rdfs:label ?clsLabel }
}

