PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?compLabel (?m * ?f AS ?kg) WHERE {
  BIND(<https://www.purl.org/futuram#V0301030103_Y2025> AS ?whole)
  ?node futuram:partOf ?whole ;
        rdf:type ?key ;
        fq:itemMass ?m ;
        fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ; fq:amount ?f ] .
  ?key rdfs:label ?compLabel .
  ?key rdfs:subClassOf <https://www.purl.org/futuram#Component> .
  FILTER NOT EXISTS {
    ?key rdfs:subClassOf ?mid .
    ?mid rdfs:subClassOf <https://www.purl.org/futuram#Component> .
    FILTER(?mid != <https://www.purl.org/futuram#Component>)
  }
}
ORDER BY DESC(?kg)

